exfalso. pose proof (Htrue_in eq_refl) as Hin. unfold fresh_var in Hin. assert (Hmaxs_ge : forall z l, In z l -> z <= maxs l) by
  (induction l; intros z H; simpl; destruct H as [Heq|Htail];
   subst; [ apply Nat.le_max_l | apply le_trans with (maxs l);
   [ apply IHl, Htail | apply Nat.le_max_r ]]). apply Hmaxs_ge in Hin. assert (Hmaxs_sub : forall l1 l2, maxs l2 <= maxs (l1 ++ l2)) by
  (induction l1; simpl; intros l2; [ reflexivity | apply le_trans with (maxs (l1 ++ l2));
   [ apply IHl1 | apply Nat.le_max_r ]]). assert (Hsub : maxs (fvs_frm p) <= maxs (x :: fvs_trm t ++ fvs_frm p)) by
  (apply Hmaxs_sub). omega.

